prod 환경에서 아래 3개 쿼리를 순서대로 실행:

쿼리 1: SELECT u.id, u.customer_id, u.email, u.name, u.status, u.created_at, u.updated_at FROM view_user u WHERE u.customer_id = 228464 AND u.email = 'jinkim@fansation.net';

쿼리 2: SELECT id, customer_id, required, db_created_at FROM flex_auth.customer_credential_t_otp_setting WHERE customer_id = 228464;

쿼리 3: SELECT a.id, a.customer_id, a.email, a.status, a.locked, a.password_updated_at, a.created_at FROM flex_auth.account a WHERE a.email = 'jinkim@fansation.net';
